#!/usr/bin/env python3# -*- coding: utf-8 -*-"""AU_COMEX_AU.py因子: AU_COMEX_AU = COMEX黄金期货主力收盘价（美元/盎司）公式: 数据采集（无独立计算公式）当前状态: [OK] 正常- 数据源: AKShare futures_foreign_hist(symbol='GC')，L1权威- 采集逻辑: 取'close'列最新一行- obs_date: 数据日期- bounds: [1000.0, 4000.0]美元/盎司（历史区间）订阅优先级: 无需付费替代付费源: 无"""import sys, os as _ossys.path.insert(0, _os.path.join(_os.path.dirname(_os.path.abspath(__file__)), ".."))from common.db_utils import ensure_table, save_to_db, get_pit_dates, get_latest_valuefrom datetime import datetimeimport functoolsprint_enc = functools.partial(print, flush=True)FACTOR_CODE = "AU_COMEX_AU"SYMBOL = "AU"BOUNDS = (1000.0, 4000.0)def fetch():    """L1: AKShare COMEX黄金期货（GC）"""    print_enc("[L1] AKShare futures_foreign_hist(symbol='GC')...")    import warnings; warnings.filterwarnings('ignore')    import akshare as ak    df = ak.futures_foreign_hist(symbol="GC")    if df is None or df.empty:        raise ValueError("no data")    latest = df.sort_values("date", ascending=False).iloc[0]    raw_value = float(latest["close"])    obs_date_str = str(latest["date"])[:10]    obs_date = datetime.strptime(obs_date_str, "%Y-%m-%d").date()    print_enc(f"[L1] COMEX_AU=${raw_value} obs={obs_date}")    return raw_value, obs_dateif __name__ == "__main__":    import warnings; warnings.filterwarnings('ignore')    pub_date, obs_date = get_pit_dates()    if pub_date is None:        print("-- 非交易日，跳过"); sys.exit(0)    ensure_table()    print(f"=== {FACTOR_CODE} === pub={pub_date} obs={obs_date}")    try:        raw_value, obs_date = fetch()    except Exception as e:        print(f"[L1] 失败: {e}")        val = get_latest_value(FACTOR_CODE, SYMBOL)        if val is not None:            print(f"[L4] 兜底: {val}")            save_to_db(FACTOR_CODE, SYMBOL, pub_date, obs_date, val,                       source="db_回补", source_confidence=0.5)        else:            print(f"[WARN] {FACTOR_CODE} 所有数据源均失败")        sys.exit(0)    if not (BOUNDS[0] <= raw_value <= BOUNDS[1]):        print(f"[WARN] {FACTOR_CODE}={raw_value} 超出bounds{BOUNDS}，跳过")        sys.exit(0)    save_to_db(FACTOR_CODE, SYMBOL, pub_date, obs_date, raw_value,               source="COMEX Gold (GC) via AKShare", source_confidence=1.0)    print(f"[OK] {FACTOR_CODE}={raw_value} obs={obs_date}")